INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_infracoes' LIMIT 1), 'Na Av. Epitácio Pessoa, em Campina Grande, semáforo exibe luz vermelha para o fluxo que segue em frente. Há placa regulamentar autorizando conversão à direita com o sinal vermelho. Condutor reduz a velocidade, verifica pedestres e ciclistas e efetua a conversão à direita. Agente da STTP pretende autuá-lo por avançar o sinal vermelho. Considerando o CTB, assinale a alternativa CORRETA:', 'A conversão à direita é permitida quando houver sinalização indicativa, observados os deveres de prudência do condutor.', 'O avanço do sinal vermelho é infração gravíssima em qualquer hipótese, ainda que exista placa de conversão à direita.', 'A conversão somente é lícita se o semáforo possuir seta verde exclusiva para a direita, independentemente de placa.', 'A placa de conversão autoriza apenas veículos de transporte coletivo, não se estendendo a automóveis de passeio.', NULL, 'A', 'caso_pratico', 'caso_pratico', 4, '{"o_que_testa":"Exceção ao art. 208 mediante conversão à direita com sinalização permissiva (art. 44-A).","fundamento_legal":"CTB, art. 44-A: é livre o movimento de conversão à direita diante de sinal vermelho do semáforo onde houver sinalização indicativa que permita essa conversão, observados os arts. 44, 45 e 70. CTB, art. 208: avançar o sinal vermelho, exceto onde houver sinalização que permita a livre conversão à direita prevista no art. 44-A.","passo_a_passo":["Há placa autorizando conversão à direita no vermelho — hipótese do art. 44-A.","A) Correta: reproduz a regra do art. 44-A com observância dos deveres de prudência.","B) Erra: o art. 208 expressamente excepciona a conversão com sinalização.","C) Erra: não exige seta verde; basta sinalização indicativa.","D) Erra: a norma não restringe a veículos de coletivo."],"pegadinha":"Candidato aplica o art. 208 sem a ressalva do art. 44-A ou exige seta verde inexistente na lei.","macete":"Vermelho + placa de conversão à direita = pode converter (art. 44-A), com prudência (arts. 44 e 45).","estudo_reverso":["CTB art. 44","CTB art. 44-A","CTB art. 208"]}'::jsonb, '{"semaforo","conversao","art_208","art_44-A"}'::text[]);